import React, { useState, useRef, useEffect } from 'react';
import { QuestionData } from '../types';
import FormattedQuestion from './FormattedQuestion';

interface AnalysisSheetProps {
  title: string;
  questionData: QuestionData;
  logoDataUrl: string | null;
}

const isValuable = (val: any): val is string => {
  return typeof val === 'string' && val.trim() !== '' && val.toLowerCase() !== 'null';
};

const AnalysisSheet: React.FC<AnalysisSheetProps> = ({ title, questionData, logoDataUrl }) => {
  const [visibleVocabCount, setVisibleVocabCount] = useState<number | null>(null);
  const vocabBlockRef = useRef<HTMLDivElement>(null);
  const displayTitle = title.replace('문제지', '해설지');

  useEffect(() => {
    setVisibleVocabCount(null);
  }, [questionData]);

  useEffect(() => {
    if (visibleVocabCount === null) {
      const timer = setTimeout(() => {
        if (!vocabBlockRef.current) return;
        const container = vocabBlockRef.current;
        const heading = container.querySelector('h4');
        const list = container.querySelector('ul');
        const firstItem = list?.querySelector('li');
        if (!heading || !list || !firstItem) {
          setVisibleVocabCount(questionData.vocabulary.length);
          return;
        }

        // Use a small safety margin to ensure we don't exceed the page height
        const sheet = container.closest('.analysis-sheet');
        if (!sheet) return;

        const footer = sheet.querySelector('.sheet-footer');
        const footerRect = footer?.getBoundingClientRect();
        const containerRect = container.getBoundingClientRect();

        if (footerRect) {
            const availableHeight = footerRect.top - containerRect.top - 40;
            const headingH = heading.offsetHeight + 10;
            const itemH = firstItem.offsetHeight || 18;
            const max = Math.floor((availableHeight - headingH) / itemH);
            setVisibleVocabCount(Math.max(0, max));
        } else {
            setVisibleVocabCount(questionData.vocabulary.length);
        }
      }, 300);
      return () => clearTimeout(timer);
    }
  }, [visibleVocabCount, questionData.vocabulary]);

  const renderTranslation = () => {
    const { translation, questionNumber } = questionData;
    if (!isValuable(translation)) return null;
    const allowed = ['31', '32', '33', '34', '38', '39', '40', '41-42'];
    if (allowed.includes(questionNumber) && translation.includes('__ANSWER__')) {
      const parts = translation.split(/__ANSWER__(.*?)__ANSWER__/);
      return parts.map((p, i) => (i % 2 === 1) ? <span key={i} className="custom-underline">{p}</span> : p);
    }
    return translation.replace(/__ANSWER__/g, '');
  };

  const vocabsToDisplay = visibleVocabCount === null ? questionData.vocabulary : questionData.vocabulary.slice(0, visibleVocabCount);

  return (
    <div className="analysis-sheet overflow-hidden relative">
      {/* Header */}
      <div className="flex justify-between items-end border-b-2 border-indigo-600 pb-2 mb-4 shrink-0">
        <span className="font-bold text-lg text-indigo-700">{displayTitle}</span>
        <span className="text-gray-600">학번 ( &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; ) 이름 ( &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; )</span>
      </div>

      <div className="grid grid-cols-[2fr_1fr] gap-8 flex-1 overflow-hidden min-h-0">
        {/* Left: Original Question Content */}
        <div className="flex flex-col min-h-0 overflow-hidden">
          <h2 className="text-2xl font-black mb-3 shrink-0">{questionData.questionNumber.replace('-', '~')}</h2>
          <div className="overflow-hidden">
             <FormattedQuestion data={questionData} />
          </div>
        </div>

        {/* Right: Analysis & Translation */}
        <div className="border-l border-gray-100 pl-6 flex flex-col min-h-0 overflow-hidden">
          <h3 className="text-xl font-bold mb-3 border-b pb-1 shrink-0">해석</h3>
          <div className="text-[9.2pt] text-gray-800 text-justify leading-relaxed mb-4 italic overflow-hidden shrink-0">
            {renderTranslation()}
          </div>

          {isValuable(questionData.grammarCorrection) && (
            <div className="bg-red-50 text-red-600 p-2 rounded border border-red-100 mb-4 text-xs font-bold shrink-0">
              {questionData.grammarCorrection}
            </div>
          )}

          <div className="shrink-0 mb-4">
            {questionData.subQuestions && questionData.subQuestions.length > 0 ? (
              <div className="space-y-0.5">
                {questionData.subQuestions.map(sq => (
                  <p key={sq.questionNumber} className="text-indigo-600 font-bold text-[9.5pt]">
                    {sq.questionNumber}번 정답: {sq.answer}
                  </p>
                ))}
              </div>
            ) : (
              <p className="text-indigo-600 font-bold text-base">정답: {questionData.answer || '미제공'}</p>
            )}
          </div>

          <div className="flex-1 min-h-0 flex flex-col overflow-hidden" ref={vocabBlockRef}>
            <h4 className="text-lg font-bold border-t pt-3 mb-2 shrink-0">어휘 및 어구</h4>
            <ul className="space-y-0.5 overflow-hidden text-[8.8pt] list-none">
              {vocabsToDisplay.map((item, i) => (
                <li key={i} className="flex gap-2 whitespace-nowrap overflow-hidden">
                  <span className="shrink-0 inline-block w-3 h-3 border border-gray-400 mt-0.5 bg-white"></span>
                  <span className="truncate">{item.word} - {item.meaning}</span>
                </li>
              ))}
            </ul>
          </div>
        </div>
      </div>

      {/* Footer */}
      <div className="sheet-footer mt-auto border-t-2 border-indigo-600 pt-3 flex justify-end shrink-0">
        {logoDataUrl && <img src={logoDataUrl} alt="logo" className="h-10 w-auto opacity-80" />}
      </div>
    </div>
  );
};

