const fileToBase64 = (file: File): Promise<string> =>
  new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
    reader.onerror = error => reject(error);
  });

const sanitizeAIResponse = (data: any[]): AnalysisDataMap => {
  const result: AnalysisDataMap = {};
  data.forEach((item) => {
    if (item && item.questionNumber) {
      result[item.questionNumber] = item as QuestionData;
    }
  });
  return result;
};

export default function App() {
  const [examFile, setExamFile] = useState<File | null>(null);
  const [solutionFile, setSolutionFile] = useState<File | null>(null);
  const [logoFile, setLogoFile] = useState<File | null>(null);
  const [logoDataUrl, setLogoDataUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isProcessed, setIsProcessed] = useState(false);
  const [selectedQuestions, setSelectedQuestions] = useState<string[]>([]);
  const [analysisData, setAnalysisData] = useState<AnalysisDataMap | null>(null);
  const [examTitle, setExamTitle] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loadingMessage, setLoadingMessage] = useState('파일을 분석 중입니다... (최대 1분 소요)');
  const [pdfProgress, setPdfProgress] = useState<string | null>(null);

  const previewRef = useRef<HTMLDivElement>(null);
  const isCancelledRef = useRef(false);

  useEffect(() => {
    if (!logoFile) {
      setLogoDataUrl(null);
      return;
    }
    const reader = new FileReader();
    reader.onloadend = () => setLogoDataUrl(reader.result as string);
    reader.readAsDataURL(logoFile);
  }, [logoFile]);

  const generateAnalysis = async () => {
    if (!examFile) {
      setError("시험지 파일을 선택해주세요.");
      return;
    }

    setIsLoading(true);
    setIsProcessed(false);
    setError(null);
    setAnalysisData({});
    isCancelledRef.current = false;
    setExamTitle(examFile.name.replace(/\.[^/.]+$/, ""));

    try {
      setLoadingMessage('AI와 연결 중입니다...');
      // Use the correct initialization for GoogleGenAI with named parameter
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const examFileBase64 = await fileToBase64(examFile);
      const parts: any[] = [
        { text: geminiPrompt(selectedQuestions) },
        { inlineData: { mimeType: examFile.type, data: examFileBase64 } }
      ];

      if (solutionFile) {
        const solBase64 = await fileToBase64(solutionFile);
        parts.push({ text: "\nHere is the solution sheet:" });
        parts.push({ inlineData: { mimeType: solutionFile.type, data: solBase64 } });
      }

      setLoadingMessage('AI가 해설을 생성하고 있습니다...');
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts },
        config: {
          responseMimeType: "application/json",
          responseSchema: geminiSchema,
        },
      });

      if (isCancelledRef.current) return;

      const jsonText = response.text;
      if (jsonText) {
        const parsed = JSON.parse(jsonText);
        const sanitized = sanitizeAIResponse(parsed);
        setAnalysisData(sanitized);
        setIsProcessed(true);
      } else {
        throw new Error("AI가 유효한 데이터를 반환하지 않았습니다.");
      }
    } catch (err: any) {
      setError(`오류 상세: ${err.message || '알 수 없는 오류'}`);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDownload = async () => {
    if (!previewRef.current || !analysisData) return;

    setPdfProgress("PDF 생성 준비 중...");
    try {
      const pdf = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
      const sheets = Array.from(previewRef.current.querySelectorAll('.analysis-sheet')) as HTMLElement[];

      for (let i = 0; i < sheets.length; i++) {
        setPdfProgress(`PDF 생성 중... (${i + 1}/${sheets.length} 페이지)`);
        const canvas = await html2canvas(sheets[i], {
          scale: 3,
          useCORS: true,
          backgroundColor: '#ffffff',
        });
        if (i > 0) pdf.addPage();
        pdf.addImage(canvas, 'JPEG', 0, 0, 210, 297, undefined, 'FAST');
      }

      pdf.save(`${examTitle}_해설지.pdf`);
    } catch (e: any) {
      setError(`PDF 생성 실패: ${e.message}`);
    } finally {
      setPdfProgress(null);
    }
  };

  const sortedAnalysisData = useMemo(() => {
    if (!analysisData) return [];
    return Object.values(analysisData).sort((a, b) => {
      const numA = parseInt(a.questionNumber, 10) || 0;
      const numB = parseInt(b.questionNumber, 10) || 0;
      return numA - numB;
    });
  }, [analysisData]);

  return (
    <div className="flex flex-col min-h-screen">
      {/* Move CSS keyframes into a style tag inside the React tree */}
      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes fadeInUp {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
      ` }} />
      <div className="app-wrapper max-w-[1400px] w-full mx-auto my-8 rounded-3xl shadow-2xl overflow-hidden bg-white/80 backdrop-blur-xl border border-gray-200 flex flex-col animate-[fadeInUp_0.6s_ease-out]">
        <header className="text-center bg-gradient-to-br from-[#0F172A] via-[#1E3A8A] to-[#2563EB] text-white py-12 px-8 relative overflow-hidden">
          <div className="absolute inset-0 bg-[radial-gradient(circle,rgba(0,212,255,0.1)_0%,transparent_70%)] animate-pulse" />
          <h1 className="text-4xl font-bold relative z-10 drop-shadow-lg mb-2">AI 영어 모의고사 해설지 생성기</h1>
          <p className="text-lg text-white/90 relative z-10">영어 모의고사 PDF를 업로드하여 문항별 맞춤 해설지를 만들어보세요.</p>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-[350px_1fr] gap-8 p-8 flex-1">
          {/* Controls */}
          <aside className="bg-white rounded-2xl shadow-lg border border-gray-100 p-6 overflow-y-auto space-y-6">
            <h2 className="text-xl font-bold text-[#1E3A8A] border-b-2 border-[#1E3A8A] pb-3 mb-6">설정</h2>

            <DropZone onFileDrop={setExamFile} file={examFile} title="1. 시험지 업로드" disabled={isLoading} />
            <DropZone onFileDrop={setSolutionFile} file={solutionFile} title="2. 정답지 업로드 (선택)" disabled={isLoading} />
            <DropZone onFileDrop={setLogoFile} file={logoFile} title="3. 로고 업로드 (선택)" disabled={isLoading} />

            {error && <div className="bg-red-50 text-red-500 border border-red-100 rounded-xl p-4 text-sm whitespace-pre-wrap shadow-sm">{error}</div>}

            <div className="space-y-3">
              <label className="block font-semibold text-gray-800">4. 문항 선택</label>
              <div className="grid grid-cols-2 gap-2">
                <button onClick={() => setSelectedQuestions(ALLOWED_QUESTIONS)} disabled={isLoading} className="py-2 bg-blue-50 text-blue-700 font-medium rounded-lg hover:bg-blue-100 transition-colors disabled:opacity-50 text-sm">전체 선택</button>
                <button onClick={() => setSelectedQuestions([])} disabled={isLoading} className="py-2 bg-blue-50 text-blue-700 font-medium rounded-lg hover:bg-blue-100 transition-colors disabled:opacity-50 text-sm">전체 해제</button>
              </div>
              <select
                multiple
                className="w-full h-48 p-3 bg-white border border-gray-200 rounded-xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 outline-none transition-all text-gray-700"
                value={selectedQuestions}
                onChange={(e) => setSelectedQuestions(Array.from(e.target.selectedOptions, opt => opt.value))}
                disabled={isLoading}
              >
                {ALLOWED_QUESTIONS.map(q => <option key={q} value={q} className="p-1">{q.replace('-', '~')}번</option>)}
              </select>
              <p className="text-xs text-gray-400">Ctrl 또는 Shift 키를 눌러 다중 선택 가능</p>
            </div>

            <div className="space-y-4 pt-4">
              <button 
                className="w-full py-4 bg-gradient-to-r from-blue-700 to-blue-800 text-white font-bold rounded-xl shadow-lg shadow-blue-100 hover:-translate-y-0.5 transition-all disabled:from-gray-300 disabled:to-gray-400 disabled:translate-y-0"
                onClick={generateAnalysis}
                disabled={!examFile || selectedQuestions.length === 0 || isLoading}
              >
                {isLoading ? '생성 중...' : '해설지 생성'}
              </button>

              {isLoading && (
                <div className="flex flex-col items-center gap-3 py-4">
                  <div className="flex items-center gap-3">
                    <div className="w-6 h-6 border-4 border-blue-100 border-l-blue-600 rounded-full animate-spin" />
                    <span className="text-gray-500 text-sm">{loadingMessage}</span>
                  </div>
                  <button onClick={() => isCancelledRef.current = true} className="text-sm font-medium text-gray-400 hover:text-gray-600">중지</button>
                </div>
              )}

              {isProcessed && !isLoading && sortedAnalysisData.length > 0 && (
                <button 
                  className="w-full py-4 bg-blue-700 text-white font-bold rounded-xl shadow-xl hover:-translate-y-0.5 transition-all"
                  onClick={handleDownload}
                >
                  PDF로 다운로드
                </button>
              )}
            </div>
          </aside>

          {/* Preview */}
          <main className="bg-gray-50 rounded-2xl flex flex-col items-center p-8 overflow-y-auto min-h-[600px] border border-gray-100">
            {isLoading ? (
              <div className="flex flex-col items-center justify-center h-full text-gray-400">
                <div className="w-10 h-10 border-4 border-blue-100 border-l-blue-600 rounded-full animate-spin mb-4" />
                <p>{loadingMessage}</p>
              </div>
            ) : sortedAnalysisData.length > 0 ? (
              <div ref={previewRef} className="flex flex-col gap-10 scale-[0.6] sm:scale-[0.8] lg:scale-100 origin-top">
                {sortedAnalysisData.map(data => (
                  <AnalysisSheet key={data.questionNumber} title={examTitle} questionData={data} logoDataUrl={logoDataUrl} />
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center h-full text-gray-400 text-center space-y-2 border-2 border-dashed border-gray-200 rounded-2xl w-full">
                <p className="text-lg">설정을 완료하고 '해설지 생성'을 눌러주세요.</p>
                <p className="text-sm">분석 결과가 여기에 표시됩니다.</p>
              </div>
            )}
          </main>
        </div>
      </div>

      <footer className="w-full py-8 text-center text-gray-400 text-sm mt-auto">
        <p>© 2025 KH KIM. All Rights Reserved.</p>
      </footer>

      {pdfProgress && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[1000] flex items-center justify-center text-white">
          <div className="bg-white text-gray-900 p-10 rounded-2xl shadow-2xl flex flex-col items-center gap-6">
            <div className="w-10 h-10 border-4 border-blue-100 border-l-blue-600 rounded-full animate-spin" />
            <span className="font-bold text-lg">{pdfProgress}</span>
          </div>
        </div>
      )}
    </div>
  );
}
